import{_ as r,c as i,o as t,a5 as l,j as a}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.20：连接状态可视化与稳定性提升","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.20.md","filePath":"changelog/v1.1.20.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.20.md"};function h(d,e,n,s,c,b){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="v1-1-20-连接状态可视化与稳定性提升" tabindex="-1">v1.1.20：连接状态可视化与稳定性提升 <a class="header-anchor" href="#v1-1-20-连接状态可视化与稳定性提升" aria-label="Permalink to “v1.1.20：连接状态可视化与稳定性提升”">​</a></h1><p><strong>发布日期</strong>：2026年1月14日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新在 <code>/connect</code> 对话框中<strong>显示已连接的提供商</strong>，提升了使用体验，并修复了多个稳定性问题。</p><hr><h2 id="新功能-连接状态可视化" tabindex="-1">新功能：连接状态可视化 <a class="header-anchor" href="#新功能-连接状态可视化" aria-label="Permalink to “新功能：连接状态可视化”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在 <code>/connect</code> 对话框中，现在可以看到哪些提供商已经连接成功，哪些还需要连接。</p><h3 id="对你有什么好处" tabindex="-1">对你有什么好处？ <a class="header-anchor" href="#对你有什么好处" aria-label="Permalink to “对你有什么好处？”">​</a></h3><p>之前：</p><ul><li>不清楚自己已经连接了哪些提供商</li><li>可能重复配置已经连接好的服务</li><li>切换提供商时需要手动记住</li></ul><p>现在：</p><ul><li>清晰看到已连接的提供商</li><li>一目了然知道哪些还可用</li><li>更容易管理多个 AI 账户</li></ul><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><ol><li>输入 <code>/connect</code></li><li>查看列表，已连接的提供商会显示状态</li><li>选择需要配置或切换的提供商</li><li>完成配置</li></ol><hr><h2 id="问题修复-桌面侧边栏-加载更多" tabindex="-1">问题修复：桌面侧边栏&quot;加载更多&quot; <a class="header-anchor" href="#问题修复-桌面侧边栏-加载更多" aria-label="Permalink to “问题修复：桌面侧边栏&quot;加载更多&quot;”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>桌面应用侧边栏的&quot;加载更多&quot;按钮在点击后不会正确加载更多内容，需要重复点击。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>&quot;加载更多&quot;按钮现在能正常工作，一次点击即可加载更多历史记录。</p><hr><h2 id="问题修复-桌面应用密码认证" tabindex="-1">问题修复：桌面应用密码认证 <a class="header-anchor" href="#问题修复-桌面应用密码认证" aria-label="Permalink to “问题修复：桌面应用密码认证”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>设置了 <code>OPENCODE_SERVER_PASSWORD</code> 环境变量后，桌面应用可能无法正常工作。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>桌面应用现在完全支持服务器密码认证，可以安全地与本地 CLI 服务通信。</p><blockquote><p>💡 <strong>密码认证</strong>：用于在桌面应用和 CLI 之间建立安全连接，防止未授权访问。</p></blockquote><hr><h2 id="问题修复-内存泄漏" tabindex="-1">问题修复：内存泄漏 <a class="header-anchor" href="#问题修复-内存泄漏" aria-label="Permalink to “问题修复：内存泄漏”">​</a></h2><h3 id="之前的问题-2" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-2" aria-label="Permalink to “之前的问题”">​</a></h3><p>长时间运行桌面应用可能会出现内存泄漏，占用过多系统资源。</p><h3 id="现在的情况-2" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-2" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了 Footer 组件中的超时跟踪问题，防止内存泄漏。现在可以长时间稳定运行。</p><hr><h2 id="其他改进" tabindex="-1">其他改进 <a class="header-anchor" href="#其他改进" aria-label="Permalink to “其他改进”">​</a></h2><ul><li><strong>去重文件引用</strong>：发送给 AI 的提示中不再包含重复的文件引用，节省 token</li><li><strong>计划模式改进</strong>：在非 git worktree 环境下也能正常使用计划模式</li><li><strong>Codex 会话优化</strong>：跳过 Codex OAuth 会话中的重复系统提示</li></ul><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用桌面应用</td><td>✅ 升级（修复多个问题）</td></tr><tr><td>使用多个 AI 提供商</td><td>✅ 升级（连接状态可视化）</td></tr><tr><td>设置了密码认证</td><td>✅ 升级（桌面应用支持）</td></tr><tr><td>只用 TUI，且没发现问题</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',42),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),l('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>修复桌面侧边栏中的&quot;加载更多&quot;按钮行为</li><li>修复在非 git worktree 环境下的计划模式</li><li>跳过 Codex OAuth 会话中的重复系统提示</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>修复 Docker 镜像中 SST 重命名后的提示</li><li>在 /connect 对话框中显示已连接的提供商</li><li>去重发送提示中的文件引用</li><li>在 Footer 组件中跟踪所有超时以防止内存泄漏</li><li>使 TUI 在设置了 OPENCODE_SERVER_PASSWORD 时也能工作</li></ul><h3 id="sdk" tabindex="-1">SDK <a class="header-anchor" href="#sdk" aria-label="Permalink to “SDK”">​</a></h3><ul><li>为 ToolContext 类型添加缺失的 metadata() 和 ask() 定义</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><p>感谢 21 位社区贡献者的参与，包括：</p><ul><li>@LeonMueller-OneAndOnly：密码认证支持</li><li>@AksharP5：连接状态可视化</li><li>@sauerdaniel：内存泄漏修复</li><li>@felixzsh：文件引用去重</li><li>@goniz：Docker 镜像修复</li><li>以及其他 16 位贡献者</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const _=r(o,[["render",h]]);export{u as __pageData,_ as default};
